import React from "react";

export default function ModalFeedback(props) {
  if (!props.open) return null;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        backgroundColor: "rgba(0, 0, 0, 0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      {" "}
      <button className="closeBtn" onClick={() => props.setOpenFeedback(false)}>
        ✕
      </button>{" "}
      {/* Modal de Feedback */}
      {props.open && (
        <div
          style={{
            backgroundColor: "#252533",
            width: "90%",
            maxWidth: "360px",
            height: "360px",
            position: "relative",
            borderRadius: "8px",
            padding: "50px",
          }}
        >
          <div>
            <h2
              style={{
                justifyContent: "center",
                display: "flex",
                marginTop: "1px",
                marginBottom: "10px",
              }}
            >
              {" "}
              Feedback
            </h2>
          </div>
          <textarea
            placeholder="Digite seu feedback sobre as respostas..."
            value={props.feedback}
            onChange={(e) => props.setFeedback(e.target.value)}
            className="feedbackTextarea"
          />
          <div className="modalFooter">
            <button
              onClick={() => props.setOpenFeedback(false)}
              className="cancelBtn"
            >
              Cancelar
            </button>
            <button
              onClick={() => {
                props.salvarEmArquivo();
                props.setOpenFeedback(false);
              }}
              className="salvarBtn"
            >
              💾 Salvar
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
